import{queryClient}from'@/lib/queryClient';export const queryCache={invalidate(key:string|string[]):void{queryClient.invalidateQueries({queryKey:Array.isArray(key)?key:[key]});},invalidateAll():void{queryClient.invalidateQueries();},prefetch<T>(key:string|string[],fetcher:()=>Promise<T>):void{queryClient.prefetchQuery({queryKey:Array.isArray(key)?key:[key],queryFn:fetcher});},setData<T>(key:string|string[],data:T):void{queryClient.setQueryData(Array.isArray(key)?key:[key],data);},getData<T>(key:string|string[]):T|undefined{return queryClient.getQueryData(Array.isArray(key)?key:[key]);},remove(key:string|string[]):void{queryClient.removeQueries({queryKey:Array.isArray(key)?key:[key]});}};
